const { Lambda } = require('@vercel/build-utils');

exports.version = 3;

exports.build = async ({ entrypoint, files }) => {
  // Mimics builders that finish work but leak timers/sockets and keep the CLI alive.
  setInterval(() => {}, 60_000);

  return {
    output: new Lambda({
      files: {
        [entrypoint]: files[entrypoint],
      },
      runtime: 'provided',
      handler: entrypoint,
    }),
  };
};
